const input = $input.first().json.query || '';

// Parse kind and namespace from the input
const kindMatch = input.match(/kind\s*=\s*(\w+)/i);
const nsMatch = input.match(/namespace\s*=\s*([\w-]+)/i);

const must = [];
if (kindMatch && kindMatch[1].toLowerCase() !== 'all') {
  must.push({ key: 'metadata.kind', match: { value: kindMatch[1] } });
}
if (nsMatch && nsMatch[1].toLowerCase() !== 'all') {
  must.push({ key: 'metadata.namespace', match: { value: nsMatch[1] } });
}

const body = { limit: 200, with_payload: { include: ['metadata'] } };
if (must.length > 0) body.filter = { must };

return [{ json: { qdrantBody: JSON.stringify(body) } }];

const qdrantResponse = $('Query Qdrant').first().json;
const points = qdrantResponse.result?.points || [];

if (points.length === 0) {
  return [{ json: { response: 'No matching Kubernetes resources found.' } }];
}

const lines = points.map(p => {
  const m = p.payload?.metadata || {};
  return `${m.kind || '?'} | ${m.name || '?'} | ${m.namespace || 'cluster-scoped'} | ${m.spec_summary || '-'}`;
});

const response = `Kind | Name | Namespace | Details\n` + lines.join('\n') + `\n\nTotal: ${points.length} resources`;

return [{ json: { response } }];
